-- ============================================
-- 一、篮球规则
-- ============================================

INSERT INTO basketball_knowledge (title, content, category, sub_category, tags, difficulty, is_published, view_count) VALUES

('FIBA国际篮联最新规则详解', '【知识分类】篮球规则 / FIBA规则\n\n【概述】\n国际篮球联合会（FIBA）是全球篮球运动的管理机构，其规则适用于奥运会、世界杯及各洲际锦标赛。FIBA规则每两年修订一次，以保证比赛的公平性和观赏性。以下为最新版本的核心规则详解。\n\n【比赛通则】\n\n1. 比赛时间\n· 每场比赛分为4节，每节10分钟（FIBA，NBA为12分钟）\n· 节间休息2分钟，半场休息15分钟\n· 加时赛5分钟\n· 暂停：上半场2次，下半场3次，加时赛1次\n\n2. 场地规格\n· 长28米、宽15米\n· 三分线距离篮筐6.75米（NBA为7.24米）\n· 罚球线距篮板5.8米\n· 合理冲撞区：篮下1.25米半径半圆\n\n3. 球员人数\n· 每队场上5人\n· 替补席最多7人\n· 每队总计最多12人\n\n【违例规则】\n\n1. 走步违例\n· 中枢脚移动后重新落地\n· 接球后三步及以上\n· 运球前中枢脚先离地\n· 判定标准：第0步→第1步→第2步（新规则）\n\n2. 两次运球违例\n· 双手同时触球后再次运球\n· 运球结束后再次运球\n· 球在手中停留过久\n\n3. 回场违例\n· 前场持球人触碰到后场\n· 球回到后场后本队先触碰\n· 中线属于前场\n\n4. 进攻时限\n· 24秒进攻时限\n· 进攻篮板后重置为14秒\n· 防守犯规后根据剩余时间决定\n\n5. 其他违例\n· 脚踢球违例\n· 球出界\n· 8秒过后场的限制\n· 3秒防守区限制\n· 5秒发球时限\n\n【犯规分类】\n\n1. 侵人犯规\n· 阻挡、推人、拉人、打手\n· 进攻犯规（带球撞人）\n· 防守犯规（非法接触）\n\n2. 技术犯规\n· 不道德行为\n· 嘲讽对手或裁判\n· 过度暂停\n· 罚球：1次罚球+球权\n\n3. 违反体育道德犯规\n· 非篮球动作的粗暴犯规\n· 快攻中不必要的犯规\n· 2罚1掷：2次罚球+球权\n\n4. 取消比赛资格\n· 两次违反体育道德犯规\n· 严重暴力行为\n· 直接驱逐出场\n\n【FIBA与NBA关键区别】\n· 比赛时长：FIBA 40分钟 vs NBA 48分钟\n· 三分线：FIBA 6.75m vs NBA 7.24m（弧顶）\n· 防守三秒：FIBA无 / NBA有\n· 干扰球：FIBA球在篮筐上方可触碰 / NBA圆柱体限制\n· 犯规罚下：FIBA 5犯 / NBA 6犯\n· 暂停次数：FIBA上半场2+下半场3 / NBA每场比赛7次', '篮球规则', 'FIBA规则', 'FIBA,规则,违例,犯规,国际篮联', '新手入门', 1, 120),

('NBA规则特别条款与判决标准', '【知识分类】篮球规则 / NBA规则\n\n【概述】\nNBA（美国职业篮球联赛）拥有独立的规则体系，与FIBA规则有诸多不同。NBA规则更注重比赛的观赏性和商业价值，同时对球员技术有更高的容错空间。\n\n【NBA特有规则】\n\n1. 防守三秒\n· 防守球员在禁区内停留超过3秒（无明确防守对象）\n· 被判技术犯规\n· 对方获得1次罚球+球权\n· 此规则使NBA内线防守更困难\n\n2. 背身5秒规则\n· 罚球线以下背筐运球不超过5秒\n· 限制内线无限背身单打\n· 鼓励更快的进攻节奏\n· FIBA无此规则\n\n3. 进攻干扰球\n· 球在下落且有可能进筐时被触碰\n· 球碰到篮板后在被防守触碰\n· 严格保护进攻方得分\n· 比FIBA规则更严格\n\n4. 合理冲撞区\n· NBA：篮下4英尺（约1.22米）半圆\n· FIBA：1.25米半径半圆\n· 在此区域内无进攻犯规（阻挡犯规）\n\n5. 犯规罚球规则\n· 单节第5次犯规后进入罚球状态（Bonus）\n· 加时赛第3次犯规后进入Bonus\n· 最后2分钟无球犯规：1罚1掷\n· 6犯罚下（FIBA为5犯）\n\n【回放系统】\n· 裁判可以在以下情况回看录像：\n  1. 压哨球判定\n  2. 恶意犯规升级\n  3. 比赛最后2分钟出界球权\n  4. 三分还是两分\n  5. 冲突事件处理\n\n【快攻犯规规则】\n· 快攻中的故意犯规判定更严\n· 违反体育道德犯规（Clear Path Foul）\n· 防守方最后一名球员对快攻犯规：2罚1掷\n\n【NBA规则演进趋势】\n· 鼓励进攻：限制防守动作\n· 提升速度：减少中断\n· 保护球员：严打恶意犯规\n· 科技辅助：增加回放场景\n· 与国际接轨：部分规则向FIBA靠拢', '篮球规则', 'NBA规则', 'NBA,规则,防守三秒,背身5秒,干扰球', '进阶提升', 1, 95),

('篮球裁判判罚标准与手势图解', '【知识分类】篮球规则 / 裁判判罚\n\n【概述】\n篮球裁判是比赛公正性的保障者。一场正规比赛通常由3名裁判组成（主裁+两名边裁），各自负责不同的判罚区域。理解裁判的判罚逻辑有助于更好地阅读比赛。\n\n【裁判分工】\n\n1. 主裁判（Lead/前导裁判）\n· 位置：底线附近\n· 职责：篮下区域判罚\n· 重点关注：投篮犯规、篮板犯规\n· 底线出界判定\n\n2. 边裁判（Trail/追踪裁判）\n· 位置：弧顶-半场区域\n· 职责：外线区域判罚\n· 重点关注：运球违例、三分投篮犯规\n· 负责24秒计时\n\n3. 中裁判（Center/中央裁判）\n· 位置：无球侧\n· 职责：弱侧区域判罚\n· 重点关注：无球犯规、掩护犯规\n· 协助边裁判和主裁判\n\n【判罚原则】\n\n1. 有利无利原则\n· 判罚不应惩罚被犯规方\n· 如果被犯规方仍有进攻优势则延迟哨\n\n2. 尺度一致性\n· 全场比赛保持统一的判罚尺度\n· 身体对抗的容忍度赛前明确\n\n3. 位置优先\n· 有最佳视野的裁判主导判罚\n· 其他裁判辅助\n\n4. 控制比赛\n· 防止比赛失控\n· 技术犯规作为控制手段\n· 必要时暂停比赛\n\n【常见判罚误区】\n· 防守人站住≠一定不是阻挡\n· 进攻人起跳≠一定是防守犯规\n· 球手一体原则：手触球不算犯规\n· 盖帽后身体接触：视情况判定\n\n【裁判手势速记】\n· 双手水平握拳交叉手腕→走步\n· 单手三指并拢下压→24秒违例\n· 右手食指画圈→回场违例\n· 双手交叉高举→技术犯规\n· 右手握拳→犯规停止计时\n· 右手手掌推动→阻挡犯规\n· 右手向上推出→打手犯规', '篮球规则', '裁判判罚', '裁判,判罚,手势,执裁,篮球比赛', '进阶提升', 1, 75),

('篮球违例与犯规完整界定标准', '【知识分类】篮球规则 / 违例与犯规\n\n【概述】\n违例（Violation）和犯规（Foul）是篮球比赛中的两类违规行为。两者处罚方式不同：违例导致球权转换，犯规可能导致罚球。准确理解两者的界定是参与篮球运动的基础。\n\n【违例全面界定】\n\n1. 运球违例\n· 二次运球：双手触球后再次运球\n· 运球翻腕（携带球）：手掌朝上托球\n· 非法运球：手超过球的垂直底面\n\n2. 走步违例\n· 接球后中枢脚非法移动\n· 三步上篮违反两步规则\n· 跳步落地后滑动或跨步\n· 新规第0步详解：接球时一只脚在地面=第0步\n\n3. 时间违例\n· 24秒进攻违例\n· 8秒后场违例\n· 5秒发球违例\n· 3秒防守区违例（FIBA无防守3秒）\n\n4. 空间违例\n· 回场违例\n· 球出界\n· 脚踢球\n· 干扰球（进攻/防守）\n· 罚球时提前进线\n\n【犯规全面界定】\n\n1. 防守犯规\n· 非法用手（打手）\n· 拉人、推人、阻挡\n· 非法掩护（移动掩护）\n· 夹臂、拉拽球衣\n\n2. 进攻犯规\n· 带球撞人\n· 非法掩护（进攻方）\n· 肘击\n· 非法离开位置\n\n3. 技术犯规\n· 不尊重裁判\n· 过度庆祝\n· 拖延比赛\n· 非法替补\n· 抓篮筐\n\n4. 恶意犯规（违反体育道德）\n· 不必要的暴力接触\n· 快攻犯规\n· 报复性犯规\n· 非篮球动作\n\n【争议判罚解析】\n\n| 场景 | 正确判罚 | 常见误解 |\n|------|---------|--------|\n| 盖帽干净+后续身体接触 | 无犯规 | 以为是打手 |\n| 防守人站住+侧身 | 阻挡犯规 | 以为合法防守 |\n| 球手一体（手触球） | 无犯规 | 以为打手 |\n| 进攻人主动找接触 | 防守犯规或进攻犯规 | 取决于防守人位置 |\n| 秒表剩余不足24秒被犯规 | 重置为14秒 | 以为不会重置 |', '篮球规则', '违例与犯规', '违例,犯规,走步,二次运球,阻挡,打手', '新手入门', 1, 80),

('FIBA最新规则变更解读（2024版）', '【知识分类】篮球规则 / 规则变更\n\n【概述】\nFIBA规则每两年修订，持续优化比赛公平性和流畅度。以下为2024版最新规则变更的解读分析。\n\n【主要变更内容】\n\n1. 走步规则细化\n· 明确"第0步"定义：接球时单脚在地为第0步\n· 收球时第一只落地脚为第1步\n· 简化判断：普通球员更清楚走步边界\n· 影响：更快节奏的突破被鼓励\n\n2. 假摔判罚强化\n· 假摔第一次警告\n· 第二次技术犯规\n· 裁判可以回放判断\n· FIFA式的假摔惩罚引入篮球\n\n3. 24秒规则调整\n· 进攻篮板后统一重置14秒\n· 简化了之前复杂的重置逻辑\n· 加快比赛节奏\n· 对进攻方稍微不利\n\n4. 技术犯规处罚\n· 累计2次技术犯规直接罚下\n· 比赛中任何打架直接罚下\n· 加强体育道德约束\n\n5. 发球规则\n· 最后2分钟暂停后前场发球\n· 提高最后时刻战术丰富度\n\n6. 教练挑战\n· 每队每场1次挑战机会\n· 可挑战：犯规/违例/出界\n· 挑战成功保留机会\n· 借鉴NBA经验\n\n【对比赛的影响】\n· 比赛节奏进一步加快\n· 假摔行为得到遏制\n· 教练战术参与度提高\n· 走步判罚更统一\n· 终局战术更丰富', '篮球规则', '规则变更', 'FIBA,规则更新,走步规则,假摔,教练挑战', '进阶提升', 1, 65),

('篮球比赛人数、场地与器材规格标准', '【知识分类】篮球规则 / 场地器材\n\n【概述】\n标准篮球比赛有严格的人数、场地和器材要求。了解这些标准是成为一名合格篮球参与者（球员/教练/裁判）的基础。\n\n【人数配置】\n\n1. 场上人员\n· 每队场上5人（标准）\n· 3人制篮球（FIBA 3x3）：每队场上3人\n\n2. 球队编制\n· 最多12名球员\n· 主教练1名\n· 助理教练1-3名\n· 队医1名\n· 翻译/统计/其他随队人员\n\n3. 裁判组\n· 标准比赛：3名裁判\n· FIBA重要赛事：3+1（3场上+1技术代表）\n· NBA：3裁判+回放中心\n· 业余比赛：1-2名裁判\n\n【场地标准】\n\n1. FIBA标准\n· 长度：28米\n· 宽度：15米\n· 天花板高度：至少7米\n· 线宽：5厘米\n\n2. NBA标准\n· 长度：94英尺（28.65米）\n· 宽度：50英尺（15.24米）\n· 尺寸略大于FIBA\n\n3. 关键标线\n· 三分线：FIBA 6.75m / NBA 7.24m（弧顶）6.7m（底角）\n· 罚球线：距篮板5.8m / NBA 15英尺\n· 中圈：半径1.8m\n· 限制区（油漆区）：FIBA 4.9m×5.8m / NBA 16英尺×19英尺\n\n【器材标准】\n\n1. 篮球\n· 男子标准：7号球（周长75-78cm，重量567-650g）\n· 女子标准：6号球（周长72-74cm，重量510-567g）\n· 青少年：5号球\n· FIBA认证球品牌：Molten\n· NBA官方球：Wilson（原Spalding）\n\n2. 篮筐\n· 高度：3.05米（10英尺）\n· 内径：45厘米\n· 篮板尺寸：FIBA 1.8m×1.05m / NBA 6英尺×3.5英尺\n\n3. 计时设备\n· 比赛计时器：精确到0.1秒\n· 24秒计时器：每端各一个\n· 暂停计时器\n· 犯规计数器\n\n4. 电子设备\n· LED计分板\n· 视频回放系统\n· 裁判通讯系统\n· 计时员与裁判联动系统', '篮球规则', '场地器材', '场地,器材,篮球规格,篮筐,人数配置', '新手入门', 1, 60);

-- ============================================
-- 二、战术理论
-- ============================================

INSERT INTO basketball_knowledge (title, content, category, sub_category, tags, difficulty, is_published, view_count) VALUES

('篮球战术基础理论：空间、时间与节奏', '【知识分类】战术理论 / 基础理论\n\n【概述】\n篮球战术的本质是"在时间约束下最佳利用球场空间创造得分机会"。理解战术的底层原理比记忆战术跑位更重要。以下为篮球战术的基础理论框架。\n\n【三大核心要素】\n\n1. 空间（Spacing）\n· 定义：5名球员在进攻半场的位置分布\n· 空间原则：\n  · 纵向4层（弧顶-45度-底角-篮下）各1人\n  · 横向间距5-7米\n  · 强侧3人弱侧2人为最优比例\n· 空间最大化=防守最疲劳\n· 勇士五小的秘密：5人全拉开\n\n2. 时间（Timing）\n· 24秒进攻时限分配：\n  · 0-8秒：推进过半场\n  · 8-16秒：战术跑位\n  · 16-24秒：终结进攻\n· 传球时间：最晚传球提前量0.3秒\n· 切入时机：防守人重心变化瞬间\n· 挡拆时机：掩护人站稳后0.5秒\n\n3. 节奏（Rhythm）\n· 进攻节奏类型：\n  · 快节奏（Pace>105）：太阳/勇士模式\n  · 中等节奏（Pace 98-105）：掘金/凯尔特人\n  · 慢节奏（Pace<98）：传统阵地战\n· 节奏控制方法：\n  · 推进速度\n  · 传球频率\n  · 投篮选择距离\n  · 进攻篮板策略\n\n【战术决策框架】\n\n1. 阅读防守四要素\n· 看防守阵型（人盯人/联防/混合）\n· 看防守注意力（球在哪防守在哪）\n· 看防守弱点（脚步慢的球员/防空切弱）\n· 看防守倾向（换防/延误/沉退）\n\n2. 进攻选择决策树\n持球人→无人防守→投篮\n持球人→1防1→单打\n持球人→吸引协防→突分\n持球人→挡拆→阅读掩护后防守\n无球人→防守跟得紧→反跑空切\n无球人→防守留空间→拉开要球\n\n【空间-时间-节奏的配合】\n三者的最优组合决定进攻效率。例如：\n· 好空间+正确时机+适中节奏 = 高效进攻\n· 好空间+错误时机+任何节奏 = 失误\n· 差空间+任何时机+快节奏 = 仓促出手', '战术理论', '基础理论', '战术理论,空间,时间,节奏,进攻原则', '进阶提升', 1, 85),

('进攻战术体系演进史：从传统到现代', '【知识分类】战术理论 / 体系演进\n\n【概述】\n篮球进攻战术体系在过去70年经历了革命性变化，从内线主导的慢节奏阵地战到今天的空间最大化+全员投射+无限挡拆。理解这一演进有助于把握篮球运动的发展方向。\n\n【第一阶段：内线时代（1950s-1970s）】\n· 战术核心：将球传给最好的内线球员\n· 代表体系：低位单打体系\n· 比赛节奏：极慢\n· 三分线：无（1979年才引入NBA）\n· 代表人物：张伯伦、拉塞尔、贾巴尔\n\n【第二阶段：体系化时代（1980s-1990s）】\n· 战术核心：团队配合体系\n· 代表体系：三角进攻、普林斯顿\n· 比赛节奏：中等\n· 三分线：存在但使用频率低\n· 代表人物：乔丹+菲尔杰克逊的三角进攻\n\n【第三阶段：明星单打时代（2000s）】\n· 战术核心：把球给最好的球员\n· 代表体系：ISO单打+挡拆\n· 比赛节奏：慢-中等\n· 三分线：中距离是主流得分区域\n· 代表人物：科比、艾弗森、麦迪\n\n【第四阶段：空间革命（2010s）】\n· 战术核心：空间最大化+三分\n· 代表体系：跑轰、勇士死亡五小\n· 比赛节奏：快\n· 三分线：最重要得分区域\n· 代表人物：库里、汤普森、哈登\n\n【第五阶段：全民全能（2020s至今）】\n· 战术核心：位置模糊+全能型球员\n· 代表体系：全员传导+多点发起\n· 比赛节奏：两极分化（极快/极慢）\n· 三分线：基础要求，中距离回归\n· 代表人物：约基奇、东契奇、字母哥\n\n【演进趋势总结】\n· 从内线到外线：重心外移\n· 从固定位置到位置模糊\n· 从单一战术到多元体系\n· 从慢节奏到快节奏（但保留控制）\n· 从本能到数据驱动\n· 球员技术越来越全面', '战术理论', '体系演进', '战术演进,历史,内线时代,空间革命,现代篮球', '进阶提升', 1, 70),

('防守战术体系演进：从人盯人到联防混合', '【知识分类】战术理论 / 防守体系\n\n【概述】\n防守战术的演进随着进攻战术的发展而不断调整。从最原始的人盯人到今天的混合防守体系，防守策略的复杂性已经达到了前所未有的高度。\n\n【防守体系演进的五个阶段】\n\n1. 纯人盯人时代\n· 每人盯一人，不换防\n· 优势：责任明确\n· 劣势：被掩护破解\n\n2. 纯区域联防时代\n· 每人守一个区域\n· 优势：保护内线\n· 劣势：外线漏洞\n\n3. 结合时代\n· 局部人盯人+整体区域\n· 代表作：混合联防\n· 优势：兼顾重点防守和区域覆盖\n\n4. 高强度压迫时代（2008凯尔特人/2010s热火）\n· 全场紧逼+包夹\n· 高速轮转补位\n· 边线陷阱大量使用\n\n5. 无限换防时代（勇士/火箭/凯尔特人）\n· 5个位置任意换防\n· 核心：取消防守错位\n· 要求：5名球员都能防多个位置\n\n【现代防守的核心原则】\n\n1. 限制最高价值区域\n· 数据分析：篮下>三分>中距离（防守优先级）\n· 宁愿给对方长两分也不给篮下和三分\n· 防守站位的本质是概率计算\n\n2. 迫使对手低效\n· 将球逼到对方非惯用手\n· 将球逼向边线和底线\n· 迫使对方非射手投篮\n· 迫使对方在24秒末匆忙出手\n\n3. 防守沟通革命\n· 现代防守的80%是沟通\n· 每一秒都在喊：\n  · "掩护左边！"\n  · "换！"\n  · "补了！"\n  · "回！"\n· 安静=防守崩溃\n\n【防守体系选择策略】\n· 对方无投射→收缩+联防\n· 对方有超级射手→无限换防\n· 对方有超级内线→绕前+包夹\n· 对方全队投射→3-2联防\n· 对方突破为主→2-3联防', '战术理论', '防守体系', '防守战术,人盯人,联防,无限换防,防守演进', '进阶提升', 1, 65),

('战术阵型演变史：从传统双塔到小球革命', '【知识分类】战术理论 / 阵型演变\n\n【概述】\n篮球阵型（Lineup/Five-man unit）的演变是篮球战术演进的最直观体现。从"双塔"到"一星四射"到"五小"，阵型变化反映了篮球运动对效率和空间的极致追求。\n\n【阵型演变阶段】\n\n1. 双塔阵型（传统）\n· 配置：PG+SG+SF+PF+C\n· 两大内线：一个攻一个守\n· 空间：内线拥挤\n· 代表：马刺邓肯+罗宾逊\n· 终结于：勇士革命\n\n2. 一星四射（过渡）\n· 配置：1突破核心+4三分手\n· 空间：清空内线\n· 代表：2009魔术霍华德+4射手\n· 局限性：核心单核消耗大\n\n3. 小球阵型（革命）\n· 配置：无传统中锋\n· 空间：5人全在外线\n· 代表：勇士死亡五小\n· 优势：空间最大化\n\n4. 现代全能阵型\n· 配置：5人都能投/突/传\n· 空间：动态调整\n· 代表：掘金/凯尔特人\n· 特点：位置已无意义\n\n【阵型选择原则】\n\n1. 进攻端考虑\n· 空间创造：几个非射手决定空间大小\n· 持球点：至少3个能独立发动进攻的点\n· 挡拆威胁：每个位置的挡拆能力\n\n2. 防守端考虑\n· 换防能力：几人能防多个位置\n· 护框能力：至少1人能保护篮筐\n· 篮板保护：小球时代最大的牺牲\n\n3. 对位考虑\n· 是否被对方某个位置打爆\n· 是否能打爆对方某个位置\n· 关键时刻的对位博弈\n\n【阵型的现代趋势】\n· 位置概念消亡\n· 身高分布均匀化\n· 投射能力普适化\n· 防守能力全能化\n· 单一功能性球员被淘汰', '战术理论', '阵型演变', '阵型,双塔,一星四射,小球,位置革命', '进阶提升', 1, 55),

('挡拆战术的全面理论分析', '【知识分类】战术理论 / 挡拆专项\n\n【概述】\n挡拆（Pick and Roll）是篮球运动中使用频率最高的战术动作，约占NBA所有进攻起手式的60%以上。掌握挡拆的理论基础是理解现代篮球的前提。\n\n【挡拆的数学基础】\n\n挡拆的本质是"2v2局部人数对等+空间优势"：\n· 挡拆前：1v1\n· 挡拆瞬间：短暂2v1（掩护人帮助）\n· 挡拆后：2v2但防守已被打乱\n\n防守应对的四种选择及其破解：\n\n1. 防守沉退（Drop）\n· 防守策略：大个留在篮下\n· 破解方法：持球人直接跳投\n· 适用场景：对方大个速度慢\n· 代表被破解者：戈贝尔被库里军训\n\n2. 防守延误（Hedge）\n· 防守策略：大个短暂压迫后回位\n· 破解方法：持球人延迟运球等大个回位瞬间\n· 适用场景：对方大个移动快\n· 技术要求：持球人的变速能力\n\n3. 防守换防（Switch）\n· 防守策略：两人交换防守对象\n· 破解方法：利用错位单打\n· 小打大：速度突破\n· 大打小：身体碾压\n· 代表场景：点名战术\n\n4. 防守包夹（Blitz/Trap）\n· 防守策略：双人同时压迫持球人\n· 破解方法：快速分球\n· 留下的4打3优势\n· 要求持球人有良好视野\n\n【挡拆的高级用法】\n\n1. 西班牙挡拆（Spain PNR）\n· 正常挡拆后第三人为掩护人做背掩护\n· 极其难以防守\n· 西班牙国家队发明\n\n2. 延迟挡拆（Delay）\n· 大个子运球过半场+小个子设掩护\n· 创造出人意料的防守错位\n\n3. 空挡拆（Empty Side PNR）\n· 所有人拉到另一侧\n· 单侧2v2\n· 协防无法及时到达\n· 哈登最爱的设置\n\n4. Angle挡拆\n· 挡拆角度约45度\n· 中间地带利于传球选择\n· NBA最常用的挡拆设置\n\n【挡拆防守金字塔】\n顶级挡拆防守球队的共同特征：\n1. 大个子移动速度快\n2. 沟通顶级\n3. 战术纪律严明\n4. 备选方案多样（遇挡拆不只有一种应对）', '战术理论', '挡拆专项', '挡拆,Pick and Roll,防守沉退,换防,西班牙挡拆', '专业强化', 1, 75),

('战术应用场景分析：关键时刻的战术选择', '【知识分类】战术理论 / 场景分析\n\n【概述】\n常规时间与关键时刻的战术选择完全不同。在比赛最后两分钟（关键时刻），每一个决策都可能决定胜负。分析和理解关键时刻的战术逻辑是教练水平的重要体现。\n\n【关键时刻的定义与特点】\n\n1. 关键时间窗口\n· 最后2分钟\n· 分差在5分以内\n· 每次球权都可能是决定性\n\n2. 关键时刻的特殊性\n· 防守强度最大化\n· 暂停频繁使用\n· 犯规战术出现\n· 心理压力巨大\n\n【关键时刻的战术选择】\n\n一、领先方（需要保护领先）\n\n1. 进攻端策略\n· 消耗24秒：每次进攻拖到24秒尽头\n· 高命中率出手：靠近篮筐\n· 绝对避免失误\n· 罚球好的球员持球\n\n2. 防守端策略\n· 不犯规：双手放下\n· 不放三分：防守外扩\n· 保护防守篮板：全员卡位\n· 如果对手罚球差→砍人战术\n\n二、落后方（需要追分）\n\n1. 进攻端策略\n· 快速出手（抢时间）\n· 三分优先\n· 暂停布置绝杀战术\n· 强点单打创造\n\n2. 防守端策略\n· 全场紧逼\n· 故意犯规（送罚球）\n· 赌博性抢断\n· 包夹持球人\n\n【绝杀战术库】\n· 1-4 Flat（四人拉开）\n· 星爆战术\n· 电梯门\n· 双掩护\n· UCLA Cut变化\n· 点名单打\n· 低位吊篮下\n\n【关键时刻的换人策略】\n· 进攻回合：上最好射手\n· 防守回合：上最好防守人\n· 需要篮板：上篮板王\n· 需要犯规：上罚球差球员的下家\n· 棒球式换人：每一次死球都调整阵容', '战术理论', '场景分析', '关键时刻,绝杀战术,战术选择,比赛管理,教练决策', '专业强化', 1, 60);

