-- 三、技术要领
-- ============================================

INSERT INTO basketball_knowledge (title, content, category, sub_category, tags, difficulty, is_published, view_count) VALUES

('投篮技术生物力学原理与核心要领', '【知识分类】技术要领 / 投篮技术\n\n【概述】\n投篮是篮球最核心的得分技术，其生物力学原理是理解正确投篮动作的科学基础。优秀的投篮不是"手感好"，而是可复制的标准动作+肌肉记忆。\n\n【投篮的生物力学分析】\n\n1. 动力链\n· 力量来源：脚→腿→髋→肩→肘→腕→指\n· 每个关节依次发力\n· 任何一个环节断裂都会导致投篮不稳定\n· 核心力量是投篮稳定性的保证\n\n2. 投射角度\n· 最佳出手角度：45-52度\n· 入筐角度：32-45度\n· 弧度越高，有效入筐面积越大\n· 但弧度太高降低控制力\n\n3. 球的旋转\n· 后旋（Backspin）是标准\n· 转速：约2-3转/秒\n· 后旋让球在触筐后更柔和\n· 降低了球弹出的概率\n\n【BEEF原则详解】\n\nB - Balance（平衡）\n· 双脚与肩同宽\n· 投篮侧脚略超前\n· 重心均匀分布\n· 身体正对篮筐（或微侧）\n\nE - Eyes（瞄准）\n· 瞄准篮筐前沿\n· 或瞄准篮筐后沿（因人而异）\n· 保持目光集中\n· 焦距调整：远距离看整体筐，近距离看前缘\n\nE - Elbow（肘部）\n· 投篮手肘向内收紧\n· 肘部处于球的正下方\n· 肘-手-篮筐三点一线\n· 出球时肘部完全伸展\n\nF - Follow through（跟随动作）\n· 手腕充分下压\n· 手指指向篮筐\n· 保持姿势直到球入筐\n· 跟随动作=瞄准的延续\n\n【常见错误纠正】\n\n| 错误 | 原因 | 纠正方法 |\n|------|------|--------|\n| 球左偏/右偏 | 肘外展 | 腋下夹毛巾练习 |\n| 球短（力不够） | 腿部发力不足 | 先练近筐投篮 |\n| 球旋转不足 | 手腕僵硬 | 躺姿投篮练习手腕 |\n| 投篮弧线平 | 出手角度低 | 加高弧线练习 |\n| 投篮不稳定 | 辅助手干扰 | 辅助手只扶不推 |\n\n【投篮训练进阶路线】\n1. 无球动作定型\n2. 近距离定点（篮筐正面1-2米）\n3. 中距离固定点（罚球线开始）\n4. 运球后投篮\n5. 移动中接球投篮\n6. 对抗下投篮\n7. 疲劳投篮', '技术要领', '投篮技术', '投篮,生物力学,BEEF原则,动力链,纠错', '新手入门', 1, 90),

('运球技术核心要领与科学训练方法', '【知识分类】技术要领 / 运球技术\n\n【概述】\n运球是篮球中最基础也是最难精通的技术之一。顶尖运球手的共同特征是：手腕灵活+球感极佳+抬头观察。运球能力决定了一名球员能到达的进攻高度。\n\n【运球的物理学原理】\n\n1. 手球接触\n· 手指触球面积最大化\n· 掌心始终空出\n· 手随球动（吸收球的冲击力）\n· 运球是"推球"而非"拍球"\n\n2. 球的反弹\n· 球的反弹角度=手的推球角度\n· 运球高度由推球力度决定\n· 低运球：频率快、幅度小\n· 高运球：频率慢、幅度大\n\n3. 身体重心\n· 运球时重心随球变化\n· 变向时重心先移\n· 加速时重心压低\n\n【运球能力层次】\n\nLevel 1：基础（原地+走动运球）\n· 双手交替运球\n· 高/低运球切换\n· 不看球运球\n· 达成指标：原地不看球连续运球200次\n\nLevel 2：移动（跑动+变向）\n· 行进间运球\n· 基础变向（Crossover）\n· 急停运球\n· 达成指标：全场跑动往返运球不掉球\n\nLevel 3：变向（高级变向组合）\n· 胯下运球\n· 背后运球\n· 转身运球\n· 组合变向\n· 达成指标：3种以上变向连用不掉球\n\nLevel 4：对抗（实战应用）\n· 防守压力下运球\n· 边线/底线狭窄空间控球\n· 包夹下控球\n· 达成指标：对抗练习中失误率<10%\n\nLevel 5：花式（专业级）\n· 山姆高德\n· 双球运球\n· 蒙眼运球（终极球感）\n\n【核心训练方法】\n\n1. 球感训练\n· 手指绕球（顺时针+逆时针）\n· 头部/腰部/膝盖绕球\n· 八字绕球\n· 练习时长：每天10分钟打底\n\n2. 力量训练\n· 重球训练（训练用加重球）\n· 指力训练（指卧撑/握力器）\n· 前臂训练（手腕卷重）\n\n3. 协调训练\n· 双球同时运球\n· 运球+另一只手做动作\n· 运球+跳绳\n\n4. 实战训练\n· 锥桶变向训练\n· 防守人压迫运球\n· 场地边界运球\n\n【常见错误纠正】\n· 看球→强制抬头，看教练手势\n· 运球太高→降低重心，加强腿部力量\n· 只用惯用手→非惯用手2倍训练量\n· 变向掉球→放慢速度，逐步加速', '技术要领', '运球技术', '运球,球感,变向,训练方法,纠错', '新手入门', 1, 85),

('防守技术核心要领：站位、移动与干扰', '【知识分类】技术要领 / 防守技术\n\n【概述】\n"进攻赢得比赛，防守赢得冠军。"这句话概括了防守的重要性。防守是50%身体+50%心态。优秀的防守者首先是心态积极，其次是技术过硬。\n\n【防守的四大支柱】\n\n1. 防守姿态\n· 双脚宽于肩\n· 膝盖屈至90度\n· 背部挺直，臀部下沉\n· 双手张开（一手干扰传球一手防突破）\n· 重心前倾但不过度\n\n2. 防守移动\n· 侧滑步：防守的基础移动\n· 后滑步：保持距离后退\n· 交叉追防步：被过后追赶\n· 堵位跨步：切断突破路线\n· 核心：脚不交叉、重心不升\n\n3. 防守时机\n· 掏球时机：球从地面反弹到最高点\n· 干扰投篮时机：对手出手瞬间\n· 盖帽时机：球离开手的一刹那\n· 造犯规时机：对手起跳前站稳\n\n4. 防守沟通\n· "掩护左边/右边"：告知队友掩护方向\n· "换"：换防指令\n· "补了"：补防通知\n· "我来"：承担当前防守\n· 无声防守=无效防守\n\n【一对一防守系统】\n\n防守持球人的完整流程：\n1. 靠近（Closeout）\n   · 冲刺一半距离\n   · 后半程小步减速\n   · 一手举起防投篮\n   · 到达防守位置\n\n2. 压制（Contain）\n   · 迫使持球人走非惯用手\n   · 阻止直线突破\n   · 允许朝底线方向（有底线帮助）\n   · 不允许朝中路（最危险）\n\n3. 反应（React）\n   · 被晃动后快速恢复平衡\n   · 小碎步调整\n   · 上肢继续干扰\n\n4. 终结（Contest）\n   · 投篮时垂直起跳\n   · 手臂完全伸直\n   · 不要向前扑（犯规）\n   · 落地后立即卡位抢篮板\n\n【防守球星的共同特征】\n· 极佳的横移速度\n· 强壮的臀部和大腿（防守根基）\n· 极强的心态（被过了不沮丧）\n· 出色的预判能力\n· 沟通欲望强烈\n\n【防守训练方法】\n· 侧滑步折返跑\n· 防守镜子练习（跟随进攻人移动）\n· Zig-Zag滑步训练\n· 视频分析（看自己防守站位）\n· 防守心态训练：庆祝成功的防守', '技术要领', '防守技术', '防守,防守姿态,滑步,干扰,沟通', '新手入门', 1, 75),

('传球技术要领与进阶指导', '【知识分类】技术要领 / 传球技术\n\n【概述】\n传球是篮球运动中被最严重低估的技术。伟大的传球手（斯托克顿、纳什、魔术师约翰逊）之所以伟大，是因为他们让队友变得更好。传球是连接5个人的纽带。\n\n【传球的核心要领】\n\n1. 准确性\n· 传向队友胸部位置（最佳接球点）\n· 提前量：传到队友移动方向前方\n· 力度：太轻被断，太重接不住\n· 练就"GPS传球"：闭眼也能传准\n\n2. 时间性\n· 传球窗口=0.3-0.5秒\n· 等队友空位才传=太晚\n· 在队友即将有空位时传出\n· 预判空位比看到空位更重要\n\n3. 隐蔽性\n· 不看传球方向（No-look Pass）\n· 改变传球角度和速度\n· 用身体遮挡传球动作\n· 单手/低手传球隐蔽性高\n\n【传球技术分类】\n\n基础传球：\n· 双手胸前传球：最基础最准确\n· 双手击地传球：穿透防守\n· 单手体侧传球：快速短传\n· 头上传球：越过防守\n\n进阶传球：\n· 背后传球：隐蔽且快速\n· 脑后传球：极具欺骗性\n· 棒球式长传：快攻利器\n· 口袋传球：极小空间内的魔术\n\n【传球决策模型】\n\n什么时候该传球？\n· 队友有更好的投篮机会\n· 自己被双人包夹\n· 按照战术设计需要传导\n· 24秒时间充足\n\n什么时候该投篮？\n· 自己是空位\n· 战术打死了\n· 24秒即将耗尽\n· 自己是球队最好的终结选择\n\n传球的优先顺序（按效率排列）：\n1. 空位篮下队友（最高命中率）\n2. 空位三分射手\n3. 空位中距离\n4. 被防守但位置好的内线\n5. 重新组织进攻\n\n【传球训练方法】\n· 对墙传球（不同角度/力度）\n· 移动中传球（跑动接球→传→跑）\n· 两人全场推进传球\n· 快速反应传球（教练喊方向）\n· 视频学习：观察伟大传球手的决策过程\n\n【常见传球错误】\n· 跳起传球（在空中传球容易失误）\n· 单手远离身体的传球\n· 不看接球人\n· 传球力度不当\n· 在包夹中勉强传球', '技术要领', '传球技术', '传球,准确性,隐蔽性,传球决策,训练方法', '新手入门', 1, 65);

-- ============================================
-- 四、训练方法
-- ============================================

INSERT INTO basketball_knowledge (title, content, category, sub_category, tags, difficulty, is_published, view_count) VALUES

('篮球专项体能训练完整方案', '【知识分类】训练方法 / 体能训练\n\n【概述】\n篮球是一项对身体素质要求极高的运动：需要爆发力（扣篮/突破）、速度（快攻/防守）、耐力（40分钟高强度）、灵活性（变向/防守）、力量（对抗/卡位）的全面结合。\n\n【体能训练五大模块】\n\n一、力量训练\n\n1. 下肢力量（篮球的发动机）\n· 杠铃深蹲：3组×8-12次\n· 保加利亚分腿蹲：每腿3组×10次\n· 罗马尼亚硬拉：3组×10次\n· 小腿提踵：4组×20次\n· 训练频率：每周2次\n\n2. 核心力量（力量的传递枢纽）\n· 平板支撑：4组×60秒\n· 俄罗斯转体：3组×20次\n· 悬垂举腿：3组×15次\n· 农夫行走：3组×40米\n· 训练频率：每天（分散在各训练中）\n\n3. 上肢力量（对抗能力）\n· 卧推：3组×8-10次\n· 引体向上：3组×最大次数\n· 推举：3组×10次\n· 训练频率：每周2次\n\n二、爆发力训练\n\n1. 跳跃训练（Plyometrics）\n· 跳箱：4组×8次\n· 深度跳跃：3组×6次\n· 单脚跳远：每腿3组×5次\n· 连续跨栏跳：3组×10栏\n· 训练频率：每周2次（不与力量日同天）\n\n2. 速度训练\n· 30米冲刺：6-8组\n· 折返跑：4组×全场\n· 反应起跑（听信号）：8组\n· 变向冲刺：6组×锥桶\n\n三、耐力训练\n\n· 高强度间歇训练（HIIT）：\n  · 30秒全力→30秒恢复×10\n  · 模拟比赛攻防节奏\n· 长跑：5-8公里保持基础耐力\n· 游泳：交叉训练，保护关节\n\n四、灵活性/敏捷性\n\n· 绳梯训练：每天15分钟\n· 锥桶变向跑：各种角度\n· 动态拉伸：训练前必修课\n· 瑜伽：每周1-2次\n\n五、恢复与营养\n\n· 训练后30分钟内补充蛋白质\n· 足够睡眠（7-9小时）\n· 每天饮水量：体重×0.04升\n· 筋膜放松（泡沫轴）：每天\n· 休息日：每周至少1天完全休息\n\n【训练周期规划】\n\n一周训练模板：\n周一：力量（下肢）+ 投篮\n周二：爆发力 + 运球/技术\n周三：耐力 + 战术\n周四：力量（上肢）+ 投篮\n周五：敏捷性 + 比赛\n周六：综合训练或比赛\n周日：休息/恢复\n\n【不同位置的体能侧重】\n· 后卫：速度+敏捷+耐力（轻量重次数）\n· 前锋：全面（力量和速度平衡）\n· 中锋：力量+爆发力（重量少次数）', '训练方法', '体能训练', '体能训练,力量训练,爆发力,耐力,恢复', '进阶提升', 1, 80),

('投篮专项训练计划：从入门到精通', '【知识分类】训练方法 / 投篮训练\n\n【概述】\n投篮是唯一可以通过纯粹训练量产生质的飞跃的技术。以下是分阶段的投篮训练系统，从建立动作定型到比赛级实战投篮。\n\n【阶段一：动作定型（2-4周）】\n\n训练目标：建立可复制的标准投篮动作\n\n每日训练内容：\n1. 无球动作练习（10分钟）\n   · 站立反复模拟完整投篮动作\n   · 检查BEEF每一点\n   · 形成肌肉记忆\n\n2. 近距离定型（15分钟）\n   · 篮筐正面1-2米\n   · 单手投篮（辅助手背在身后）\n   · 目标：连续命中20球\n\n3. 近距离双手（15分钟）\n   · 加辅助手（只扶不推）\n   · 篮下四个点各50球\n   · 达标率要求：80%\n\n【阶段二：距离延伸（3-6周）】\n\n每日训练内容：\n1. 中距离定点（20分钟）\n   · 罚球线开始\n   · 逐渐向两侧扩展\n   · 每个点25球\n   · 达标率：罚球线75%\n\n2. 三分线内一步（15分钟）\n   · 五个标准点\n   · 每个点20球\n   · 达标率：65%\n\n3. 罚球专项（10分钟）\n   · 模拟比赛罚球流程\n   · 深呼吸→拍球→出手\n   · 每次50球\n   · 达标率：80%\n\n【阶段三：移动投篮（4-8周）】\n\n每日训练内容：\n1. 运球后投篮（15分钟）\n   · 急停跳投\n   · 后撤步投篮\n   · 侧步投篮\n\n2. 接球投篮（15分钟）\n   · 教练/队友传球\n   · 不同角度接球\n   · 接球后快速出手\n\n3. 移动投篮（15分钟）\n   · 跑动中接球投篮\n   · 绕掩护接球投篮\n   · V-cut接球跳投\n\n【阶段四：实战模拟（持续）】\n\n每日训练内容：\n1. 对抗投篮（20分钟）\n   · 防守人施加压力\n   · 模拟比赛节奏\n   · 疲劳状态下投篮\n\n2. 比赛情境（20分钟）\n   · 计时投篮（24秒内）\n   · 关键时刻模拟（分差3分）\n   · 连续投射（模拟追分）\n\n【训练量标准】\n· 初学者：每天100-200球\n· 业余爱好者：每天200-500球\n· 半职业：每天500-1000球\n· 职业：每天1000球以上\n· 库里训练量：赛季中每天300-500球\n\n【进步跟踪】\n每周同一点测试50球，记录命中率变化曲线。持续下降是动作出问题的信号。', '训练方法', '投篮训练', '投篮训练,训练计划,动作定型,移动投篮,对抗投篮', '新手入门', 1, 85),

('篮球战术演练方法：团队训练组织指南', '【知识分类】训练方法 / 战术演练\n\n【概述】\n战术演练是连接个人技术训练和比赛的桥梁。优秀的战术演练能让球队在比赛中不假思索地执行战术，将大脑的认知负担降到最低。\n\n【战术训练四步法】\n\n第一步：白板讲解（Walk Through）\n· 时间：15-20分钟\n· 场地：不需要球场\n· 工具：战术板\n· 内容：\n  · 讲解战术跑位路线\n  · 解释每个人的角色\n  · 说明防守反应对应的变化\n  · 问答环节\n\n第二步：无对抗走位\n· 时间：20-30分钟\n· 场地：半场\n· 内容：\n  · 5人按战术路线慢速走位\n  · 不防守，不投篮\n  · 确保每个人知道自己的位置\n  · 重复直到所有人走位流畅\n\n第三步：半对抗演练\n· 时间：30-40分钟\n· 场地：半场\n· 内容：\n  · 防守方50%强度\n  · 进攻方按实战速度\n  · 不投篮只跑位\n  · 重点练习跑位时机\n  · 重复每种防守反应\n\n第四步：全对抗实战\n· 时间：30-40分钟\n· 场地：全场/半场\n· 内容：\n  · 100%比赛强度\n  · 有投篮终结\n  · 防守全力应对\n  · 教练观察修正\n  · 录像回放分析\n\n【日常战术训练安排】\n\n前锋模式（2小时内完成）：\n0:00-0:20 白板讲解当天要练的战术\n0:20-0:40 无对抗走位\n0:40-1:10 半对抗演练\n1:10-1:20 补水休息\n1:20-1:50 全对抗实战\n1:50-2:00 拉伸总结\n\n【各水平战术训练重点】\n\n初级球队（校园/业余）\n· 只练2-3套基础战术\n· 反复练习直到形成条件反射\n· 重点：传切配合+挡拆+快攻\n· 频率：每套战术每周至少练2次\n\n中级球队（高中/大学）\n· 5-8套战术\n· 包含攻防转换\n· 加入特殊战术（发球/绝杀）\n· 频率：每套战术每周练1-2次\n\n高级球队（职业/半职业）\n· 10套以上战术体系\n· 赛前针对性备战\n· 数据驱动的战术选择\n· 每个对手有不同的战术包\n\n【常见错误】\n· 跳过了白板阶段→球员不知道自己该干什么\n· 无对抗练太多→半对抗和全对抗脱节\n· 每次练新战术→老的战术全忘了\n· 不给防守方指导→防守随便防，进攻得不到锻炼', '训练方法', '战术演练', '战术演练,团队训练,四步法,训练组织,跑位', '进阶提升', 1, 60),

('赛季训练计划制定：周期化训练科学', '【知识分类】训练方法 / 训练计划\n\n【概述】\n科学的训练计划不是"每天多练就好"，而是遵循运动训练学的周期化原则（Periodization）。合理安排训练强度和恢复周期是避免伤病和持续进步的关键。\n\n【训练周期理论】\n\n1. 大周期（Macrocycle）：赛季\n· 长度：3-12个月\n· 目标：赛季最佳状态\n· 包含：准备期→比赛期→过渡期\n\n2. 中周期（Mesocycle）：月计划\n· 长度：3-6周\n· 目标：特定能力提升\n· 包含：一个明确的训练主题\n\n3. 小周期（Microcycle）：周计划\n· 长度：7天\n· 目标：一周训练安排\n· 包含：训练日+休息日的合理分布\n\n4. 超微周期：训练课\n· 长度：1-3小时\n· 目标：单次训练课\n· 包含：热身→主训→放松\n\n【赛季三阶段】\n\n一、准备期（赛前4-12周）\n\n阶段1：基础体能（前1/3）\n· 训练强度：低-中\n· 训练量：高\n· 重点：有氧基础+力量基础+柔韧性\n· 投篮：动作定型\n· 战术：白板讲解\n\n阶段2：专项强度（中1/3）\n· 训练强度：中-高\n· 训练量：中-高\n· 重点：爆发力+专项力量+速度\n· 投篮：距离延伸\n· 战术：无对抗+半对抗\n\n阶段3：赛前调整（后1/3）\n· 训练强度：高\n· 训练量：降低\n· 重点：实战模拟+恢复\n· 投篮：实战模式\n· 战术：全对抗\n\n二、比赛期（赛季中）\n\n· 训练频率：根据赛程调整\n· 比赛间训练：轻度维持训练\n· 超过3天无比赛：中等训练\n· 背靠背比赛：只做恢复（拉伸/理疗）\n· 训练强度比比赛强度低\n\n三、过渡期（赛后2-4周）\n\n· 完全休息：1周\n· 轻度恢复训练：1-3周\n· 交叉训练：游泳/骑行/瑜伽\n· 身体检查和伤病治疗\n· 心理恢复和放松\n\n【每周训练负荷波动】\n\n标准训练周：\n周一：高强度（力量/爆发力）\n周二：中强度（技术训练）\n周三：高强度（战术训练）\n周四：低强度（恢复/投篮调整）\n周五：中等强度（比赛准备）\n周六：比赛/高强度训练\n周日：休息\n\n关键原则：高强度日后必须安排低强度日或休息日。连续高强度=过度训练=伤病。\n\n【训练量渐进原则】\n\n每周增幅不超过：\n· 跑步距离：10%\n· 力量重量：5%\n· 投篮数量：15%\n· 训练时长：10%\n\n【疲劳监控指标】\n· 晨脉搏（比平时高10%=疲劳）\n· 睡眠质量\n· 肌肉酸痛程度\n· 训练意愿\n· 投篮命中率（持续下降=疲劳信号）', '训练方法', '训练计划', '训练计划,周期化,赛季准备,恢复,训练负荷', '专业强化', 1, 70),

('青少年篮球训练体系与注意事项', '【知识分类】训练方法 / 青少年训练\n\n【概述】\n青少年篮球训练与成人训练有本质区别：青少年的身体发育阶段决定了训练的侧重点和强度上限。不科学的青少年训练不但无益，还可能造成永久性损伤。\n\n【年龄阶段划分与训练重点】\n\n一、基础阶段（6-10岁）\n\n身体特点：\n· 骨骼柔软，关节灵活性好\n· 注意力时间短（<15分钟）\n· 协调性发展关键期\n\n训练重点：\n1. 趣味性第一：游戏化训练\n2. 基础运动能力：跑、跳、投、接\n3. 球感建立：简单运球、投篮\n4. 严禁专项化：尝试多种运动\n5. 比赛形式：3v3小场比赛\n\n不宜训练：\n· 高强度力量训练（影响骨骼发育）\n· 长时间单一训练（<45分钟为宜）\n· 强调胜负（打击积极性）\n· 罚跑等惩罚性训练\n\n二、基础技术阶段（10-13岁）\n\n身体特点：\n· 生长加速期开始\n· 协调性大幅提升\n· 可以开始系统训练\n\n训练重点：\n1. 技术动作标准化\n2. 基础投篮姿势定型\n3. 运球基本变向\n4. 传球准确性\n5. 基础防守站姿和移动\n6. 比赛规则理解\n\n训练比例：\n· 技术训练：60%\n· 体能训练：25%（自重训练为主）\n· 战术训练：10%\n· 理论学习：5%\n\n三、全面发展阶段（13-16岁）\n\n身体特点：\n· 身高快速增长期\n· 激素水平变化\n· 力量和耐力快速提升期\n\n训练重点：\n1. 技术精细化：进阶变向、多种投篮\n2. 位置技术：初步确定位置\n3. 战术意识：基础配合\n4. 体能训练：引入轻量负重\n5. 比赛经验：正规比赛参与\n\n注意事项：\n· 生长痛期间调整训练强度\n· 注意骨骺损伤\n· 协调性可能暂时下降（长高期）\n· 心理引导同样重要\n\n四、竞技准备阶段（16-18岁）\n\n训练重点：\n1. 专项位置训练\n2. 对抗能力提升\n3. 比赛战术体系\n4. 心理训练\n5. 体能达到比赛要求\n\n可以开始：\n· 系统力量训练（在专业指导下）\n· 高强度间歇训练\n· 比赛录像分析\n· 赛前准备和心理调节\n\n【青少年训练黄金法则】\n\n1. 安全第一\n· 任何训练不能以损伤身体为代价\n· 骨骺未闭合前禁大重量深蹲\n· 出现疼痛立即停止\n\n2. 循序渐进\n· 不跳级训练\n· 每个阶段打牢基础\n· 不要因为天赋好就拔苗助长\n\n3. 全面发展\n· 不要过早专项化\n· 不同位置技术都要接触\n· 体能全方面发展\n\n4. 保持热爱\n· 训练的终极目标是让孩子爱上篮球\n· 鼓励多于批评\n· 创造一个积极的训练环境', '训练方法', '青少年训练', '青少年,训练体系,年龄阶段,安全训练,全面发展', '新手入门', 1, 75),

('篮球伤病预防与康复训练指南', '【知识分类】训练方法 / 伤病预防\n\n【概述】\n伤病是运动员职业生涯最大的敌人。据统计，篮球运动中60%的伤病是可以通过科学的预防训练避免的。了解常见伤病及其预防方法，比球技能让你打得更久。\n\n【篮球常见伤病】\n\n一、踝关节扭伤（最常见）\n· 发生率：占篮球伤病的45%\n· 原因：落地踩脚、变向过猛\n· 预防方法：\n  1. 踝关节力量训练（单脚站立/平衡板）\n  2. 本体感觉训练\n  3. 合适的篮球鞋（中高帮）\n  4. 落地技术训练\n\n二、膝关节伤病\n\n1. 前交叉韧带（ACL）损伤\n· 发生率：严重伤病中最常见\n· 原因：急停变向、落地姿势不当\n· 预防：\n  1. 腘绳肌力量训练（平衡股四头肌）\n  2. 正确的落地姿势（膝盖对齐脚尖）\n  3. 跳跃动作训练\n\n2. 髌腱炎（跳跃膝）\n· 原因：过量跳跃、股四头肌过紧\n· 预防：充分拉伸+离心力量训练\n\n三、肩关节伤病\n· 原因：投篮过度、力量不均衡\n· 预防：肩袖肌群训练、拉伸\n\n四、下腰背痛\n· 原因：核心力量弱、姿势不良\n· 预防：加强核心训练、改善坐姿\n\n五、手指伤\n· 原因：接球姿势不正确\n· 预防：正确接球手型\n\n【赛前预防措施】\n\n1. 动态热身（15分钟）\n· 慢跑5分钟\n· 动态拉伸：高抬腿/后踢腿/侧滑步\n· 关节活动：肩/髋/膝/踝\n· 神经激活：小跳/反应训练\n\n2. 肌内效贴布/运动绷带\n· 踝关节预防性贴扎\n· 不影响活动范围\n\n3. 热身要充分\n· 身体微出汗\n· 心率达到运动状态\n\n【赛后恢复措施】\n\n1. 冷身（5-10分钟）\n· 慢跑或走路\n· 静力拉伸（每个肌群30秒）\n\n2. 冰敷\n· 有伤部位：20分钟冰敷\n· 健康部位：不需要\n\n3. 营养补给\n· 30分钟内补充蛋白质+碳水\n· 充足补水\n\n4. 泡沫轴放松\n· 大腿前侧/后侧/外侧\n· 臀部\n· 背部\n· 小腿\n\n【受伤后处理原则】\n\n急性期（48小时内）：PRICE原则\n· P - Protection：保护伤处\n· R - Rest：休息\n· I - Ice：冰敷（20分钟/次，间隔2小时）\n· C - Compression：加压包扎\n· E - Elevation：抬高伤处\n\n恢复期：\n· 逐步恢复活动\n· 从无痛范围开始\n· 物理治疗师指导\n· 不要急于回归\n\n重返赛场判断：\n· 无痛\n· 活动范围恢复\n· 力量恢复到健侧80%以上\n· 功能测试通过\n\n【预防训练每周计划】\n\n每天必做：\n· 动态热身（训练前）\n· 拉伸放松（训练后）\n\n每周2-3次：\n· 踝关节力量训练\n· 核心训练\n· 平衡训练\n\n每周1-2次：\n· 泡沫轴全方位放松\n· 瑜伽/普拉提\n· 力量训练', '训练方法', '伤病预防', '伤病,预防,踝关节,膝关节,恢复,PRICE原则', '进阶提升', 1, 65);
